// Преобразование BOQ из OCE-формата в ERPNext Project payload

const boq = $input.first().json;

// Базовый проект
const project = {
  doctype: 'Project',
  project_name: boq.project.name,
  project_type: 'External',
  status: 'Open',
  customer: boq.project.client_erpnext_id,  // должно быть замаплено заранее
  expected_start_date: boq.project.start_date,
  expected_end_date: boq.project.end_date,
  estimated_costing: boq.grand_total,
  cost_center: 'Стройка - ОЛИМП',
  company: 'ООО "Олимп"',

  // Bridge fields
  custom_oce_project_id: boq.project.id,
  custom_oce_boq_id: boq.id,
  custom_oce_boq_version: boq.version,
  custom_oce_link: `https://estimate.olimp-ural.ru/projects/${boq.project.id}`,
  custom_oce_last_sync: new Date().toISOString(),
};

// Задачи из секций BOQ
const tasks = boq.sections.map((section, idx) => {
  // Распределяем сроки секций пропорционально стоимости
  const totalProgress = boq.sections.slice(0, idx).reduce((s, c) => s + c.subtotal, 0);
  const progressRatio = totalProgress / boq.total_amount;
  const projectDays = Math.ceil(
    (new Date(boq.project.end_date) - new Date(boq.project.start_date)) / 86400000
  );

  const sectionDays = Math.ceil(projectDays * (section.subtotal / boq.total_amount));
  const startOffset = Math.ceil(projectDays * progressRatio);

  const startDate = new Date(boq.project.start_date);
  startDate.setDate(startDate.getDate() + startOffset);
  const endDate = new Date(startDate);
  endDate.setDate(endDate.getDate() + sectionDays);

  return {
    doctype: 'Task',
    subject: `${section.section_code}. ${section.section_name}`,
    status: 'Open',
    exp_start_date: startDate.toISOString().split('T')[0],
    exp_end_date: endDate.toISOString().split('T')[0],
    expected_time: sectionDays * 8,  // часы
    description: `Раздел из BOQ ${boq.id}. Сумма раздела: ${section.subtotal.toLocaleString('ru-RU')} ₽`,
    custom_oce_activity_id: section.id,
  };
});

// Material Requests из позиций типа "материал"
const materialPositions = boq.positions.filter(p => 
  p.resource_type === 'material' && p.item_code
);

const materialRequests = materialPositions.map(p => ({
  doctype: 'Material Request',
  material_request_type: 'Purchase',
  schedule_date: boq.project.start_date,
  items: [{
    item_code: p.item_code,
    qty: p.quantity,
    uom: p.uom,
    rate: p.unit_rate,
    description: p.description,
  }],
  custom_oce_boq_position_id: p.id,
}));

return [{
  json: {
    project,
    tasks,
    material_requests: materialRequests,
    summary: {
      project_name: project.project_name,
      budget: project.estimated_costing,
      tasks_count: tasks.length,
      mr_count: materialRequests.length,
    }
  }
}];

